import { useEffect, useState, useContext, useMemo } from "react";
import { AuthContext } from "./AuthContext";
import EventHeader from "./EventHeader";
import PostFeed from "./Post/PostFeed";
import EditEventModal from "./Events/EditEventModal";
import StarRating from "./components/StarRating";
import EventCommentSection from "./Events/EventCommentSection";
import "./styles/events.css";

export default function EventPage() {
    const { user } = useContext(AuthContext);

    /* =====================
       BASIC STATE
    ===================== */
    const [event, setEvent] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState("");

    /* =====================
       ADMIN
    ===================== */
    const [editingEvent, setEditingEvent] = useState(null);
    const isAdmin = String(user?.role || "").toUpperCase() === "ADMIN";

    /* =====================
       RSVP
    ===================== */
    const [rsvp, setRsvp] = useState(null);
    const [counts, setCounts] = useState({ going: 0, maybe: 0 });

    /* =====================
       ATTENDEES
    ===================== */
    const [goingAttendees, setGoingAttendees] = useState([]);
    const [maybeAttendees, setMaybeAttendees] = useState([]);
    const [attendeesLoading, setAttendeesLoading] = useState(false);
    const [attendeeQuery, setAttendeeQuery] = useState("");

    const [hash, setHash] = useState(window.location.hash);

    useEffect(() => {
        const onHashChange = () => setHash(window.location.hash);
        window.addEventListener("hashchange", onHashChange);
        return () => window.removeEventListener("hashchange", onHashChange);
    }, []);

    /* =====================
       ⭐ RATING
    ===================== */
    const [rating, setRating] = useState({
        average: 0,
        count: 0,
        myRating: null,
    });

    /* =====================
       ROUTING
    ===================== */
    const { eventId, activeTab } = useMemo(() => {
        const m = (hash || "").match(/^#\/events\/(\d+)(?:\/(\w+))?/);
        return {
            eventId: m ? Number(m[1]) : null,
            activeTab: m?.[2] || "overview",
        };
    }, [hash]);

    /* =====================
       EVENT STATUS
    ===================== */
    const eventStatus = useMemo(() => {
        if (!event?.startAt) return "UPCOMING";

        const now = new Date();
        const start = new Date(event.startAt);
        const end = event.endAt
            ? new Date(event.endAt)
            : new Date(start.getTime() + 2 * 60 * 60 * 1000);

        if (now >= start && now <= end) return "LIVE";
        if (now > end) return "ENDED";
        return "UPCOMING";
    }, [event]);

    /* =====================
       FETCH EVENT
    ===================== */
    useEffect(() => {
        if (!eventId) return;

        setLoading(true);
        fetch(`/api/events/${eventId}`)
            .then(r => {
                if (!r.ok) throw new Error("Event not found");
                return r.json();
            })
            .then(setEvent)
            .catch(e => setError(e.message))
            .finally(() => setLoading(false));
    }, [eventId]);

    /* =====================
       RSVP + COUNTS
    ===================== */
    useEffect(() => {
        if (!eventId || !user) return;

        fetch(`/api/events/${eventId}/rsvp?requesterEmail=${encodeURIComponent(user.email)}`)
            .then(r => r.json())
            .then(d => setRsvp(d.status || null))
            .catch(() => {});

        fetch(`/api/events/${eventId}/attendance`)
            .then(r => r.json())
            .then(setCounts)
            .catch(() => {});
    }, [eventId, user]);

    /* =====================
       FETCH RATING
    ===================== */
    useEffect(() => {
        if (!eventId) return;

        const url = user
            ? `/api/events/${eventId}/rating?requesterEmail=${encodeURIComponent(user.email)}`
            : `/api/events/${eventId}/rating`;

        fetch(url)
            .then(r => r.json())
            .then(setRating)
            .catch(() => {});
    }, [eventId, user]);

    /* =====================
       RSVP ACTIONS
    ===================== */
    const sendRSVP = async (status) => {
        if (!user) return;

        const res = await fetch(
            `/api/events/${eventId}/rsvp?requesterEmail=${encodeURIComponent(user.email)}&status=${status}`,
            { method: "POST" }
        );

        if (!res.ok) return alert("Unable to update RSVP");

        setRsvp(status);
        setCounts(await fetch(`/api/events/${eventId}/attendance`).then(r => r.json()));
    };

    const cancelRSVP = async () => {
        if (!user) return;

        const res = await fetch(
            `/api/events/${eventId}/rsvp?requesterEmail=${encodeURIComponent(user.email)}`,
            { method: "DELETE" }
        );

        if (!res.ok) return alert("Unable to cancel RSVP");

        setRsvp(null);
        setCounts(await fetch(`/api/events/${eventId}/attendance`).then(r => r.json()));
    };

    /* =====================
       SUBMIT RATING
    ===================== */
    const submitRating = async (value) => {
        if (!user || !event) return;

        const res = await fetch(
            `/api/events/${event.id}/rating?requesterEmail=${encodeURIComponent(user.email)}`,
            {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ rating: value }),
            }
        );

        if (!res.ok) return alert("Unable to submit rating");

        const updated = await fetch(
            `/api/events/${event.id}/rating?requesterEmail=${encodeURIComponent(user.email)}`
        ).then(r => r.json());

        setRating(updated);
    };

    /* =====================
       ADMIN ACTIONS
    ===================== */
    const saveEvent = async (updates) => {
        const res = await fetch(
            `/api/events/${event.id}?requesterEmail=${encodeURIComponent(user.email)}`,
            {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(updates),
            }
        );

        const body = await res.json();
        if (!res.ok) return alert(body.message || "Failed to update event");

        setEvent(body);
        setEditingEvent(null);
    };

    const deleteEvent = async () => {
        if (!window.confirm("Delete this event?")) return;

        const res = await fetch(
            `/api/events/${event.id}?requesterEmail=${encodeURIComponent(user.email)}`,
            { method: "DELETE" }
        );

        if (!res.ok) return alert("Failed to delete event");

        window.location.hash = "#/events";
    };

    /* =====================
       GUARDS
    ===================== */
    if (loading) return <div className="event-page">Loading…</div>;
    if (error || !event) return <div className="event-page">Event not found</div>;

    /* =====================
       RENDER
    ===================== */
    return (
        <main className="event-page">
            <EventHeader
                event={{ ...event, status: eventStatus }}
                activeTab={activeTab}
                rsvp={rsvp}
                onRSVP={sendRSVP}
                onCancelRSVP={cancelRSVP}
                isAdmin={isAdmin}
                onEdit={() => setEditingEvent(event)}
                onDelete={deleteEvent}
                canEdit={isAdmin && eventStatus !== "ENDED"}
            />

            <section className="event-content">
                {activeTab === "overview" && (
                    <div className="event-overview">
                        <div className="event-rating">
                            <StarRating
                                value={rating.myRating ?? Math.round(rating.average)}
                                disabled={!user || rsvp !== "GOING" || eventStatus !== "ENDED"}
                                onRate={submitRating}
                            />
                            <div className="rating-meta">
                                {rating.count
                                    ? `${rating.average.toFixed(1)} (${rating.count} ratings)`
                                    : "No ratings yet"}
                            </div>
                        </div>

                        <h3>Description</h3>
                        <p style={{ margin: 10 }}>{event.content || "No description provided."}</p>

                        <EventCommentSection
                            eventId={event.id}
                            eventStatus={eventStatus}
                            rsvp={rsvp}
                        />
                    </div>
                )}

                {activeTab === "posts" && <PostFeed eventId={event.id} />}
            </section>

            {editingEvent && (
                <EditEventModal
                    event={editingEvent}
                    onSave={saveEvent}
                    onClose={() => setEditingEvent(null)}
                />
            )}
        </main>
    );
}
